-- CETAS (CREATE EXTERNAL TABLE AS SELECT)

CREATE EXTERNAL TABLE dbo.baT1_BallId
WITH (
    LOCATION = 'Processed/Ball_ID/',
    DATA_SOURCE = [synapsecontainer_bigstore456_dfs_core_windows_net],
    FILE_FORMAT = SynapseDelimitedTextFormat
)
AS
SELECT * FROM dbo.baT1 WHERE BALL_ID = '2';

SELECT * FROM dbo.baT1_BallId;


CREATE EXTERNAL TABLE dbo.baT1_BallId_Parquet
WITH (
    LOCATION = 'Processed/Ball_ID_Parquet/',
    DATA_SOURCE = [synapsecontainer_bigstore456_dfs_core_windows_net],
    FILE_FORMAT = SynapseParquetFormat
)
AS
SELECT * FROM dbo.baT1 WHERE BALL_ID = '2';

SELECT * FROM dbo.baT1_BallId_Parquet;
